const feedName = $('Loop Over Items').first().json.name;
const items = $input.all();

if (items.length === 0) {
  return [{ json: { _empty: true, feedName } }];
}

return items.map(item => ({
  json: { ...item.json, feedName }
}));

const allItems = $input.all();
const now = new Date();
const windowMs = 26 * 60 * 60 * 1000;
const cutoff = new Date(now.getTime() - windowMs);

const seen = new Set();
const articles = [];

for (const item of allItems) {
  if (item.json._empty) continue;

  const pubDate = new Date(item.json.pubDate || item.json.updated || item.json.isoDate);
  if (pubDate < cutoff) continue;

  const link = item.json.link || '';
  if (!link || seen.has(link)) continue;
  seen.add(link);

  articles.push({
    title: item.json.title || '',
    link,
    content: (item.json.contentSnippet || item.json.content || item.json.description || '').substring(0, 500),
    pubDate: item.json.pubDate || item.json.updated || item.json.isoDate || '',
    feedName: item.json.feedName || 'Unknown'
  });
}

const limited = articles.slice(0, 15);

return [{
  json: {
    articles: limited,
    articleCount: limited.length
  }
}];

const response = $json.text || $json.response || $json.output || '';
const articleCount = $('Preparer prompt IA').first().json.articleCount;

// Gerer les reponses vides OU commencant par AUCUN
const trimmed = response.trim();
const isRelevant = trimmed.length > 0 && !trimmed.startsWith('AUCUN');

if (!isRelevant) {
  return [{ json: { message: '', isRelevant: false } }];
}

const today = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

const cleanResponse = response
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .replace(/_/g, '')
  .replace(/`/g, '')
  .replace(/#{1,6}\s/g, '');

let message = `\u26A1 Swift Evolution - ${today}\n\n` +
  `${articleCount} source(s) analysee(s)\n\n` +
  `${cleanResponse}`;

if (message.length > 4000) {
  message = message.substring(0, 4000) + '\n\n... (tronque)';
}

return [{ json: { message, isRelevant: true } }];

const feeds = [
  { url: 'https://forums.swift.org/c/evolution/18.rss', name: 'Swift Forums - Evolution' },
  { url: 'https://forums.swift.org/tag/concurrency.rss', name: 'Swift Forums - Concurrency' },
  { url: 'https://forums.swift.org/c/evolution/proposal-reviews/21.rss', name: 'Swift Forums - Proposal Reviews' },
  { url: 'https://github.com/swiftlang/swift-evolution/commits/main.atom', name: 'GitHub Swift Evolution' },
  { url: 'https://www.swift.org/atom.xml', name: 'Swift.org Blog' }
];

return feeds.map(f => ({ json: f }));

